import urllib.request, urllib.error
base='http://localhost:80'
files=['flag','FLAG','FLAG.txt','Flag.txt','flag.txt','flag.html','flag.php','.flag','.flag.txt','secret','secret.txt','secrets.txt','.secret','.secret.txt','hidden','hidden.txt','note.txt','notes.txt','README','README.md','readme','readme.md','TODO','todo.txt','index.bak','index.old','index.html.bak','index.html~','backup.html','old.html','old-index.html','backup.zip','backup.tar.gz']
for f in files:
    url=base+'/'+f
    try:
        with urllib.request.urlopen(url, timeout=5) as r:
            content=r.read(200)
            print(r.status, f, 'first_bytes=', content[:60])
    except urllib.error.HTTPError as e:
        if e.code!=404:
            print(e.code, f)

import urllib.request, urllib.error
base='http://localhost:80/cgi-bin/'
candidates=['test','test.cgi','printenv','env','hello','index','status','admin','upload','shell','sh','bash','cmd','execute','run','debug','view','flag','getflag']
for c in candidates:
    url=base+c
    try:
        with urllib.request.urlopen(url, timeout=5) as r:
            print(r.status, c, 'len=', len(r.read()))
    except urllib.error.HTTPError as e:
        if e.code!=404:
            print(e.code, c)
    except Exception as e:
        pass
